let blocking_ep_ptr = pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// Domain equalities for all four permission maps in both runs.
assert(post1_self_.container_perms@.dom() =~= pre_self_.container_perms@.dom());
assert(post2_self_.container_perms@.dom() =~= pre_self_.container_perms@.dom());
assert(post1_self_.process_perms@.dom() =~= pre_self_.process_perms@.dom());
assert(post2_self_.process_perms@.dom() =~= pre_self_.process_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= pre_self_.thread_perms@.dom());
assert(post2_self_.thread_perms@.dom() =~= pre_self_.thread_perms@.dom());
assert(post1_self_.endpoint_perms@.dom() =~= pre_self_.endpoint_perms@.dom());
assert(post2_self_.endpoint_perms@.dom() =~= pre_self_.endpoint_perms@.dom());

// Re-assert each ensures-forall in the proof scope so z3 instantiates them in
// both runs against the same key (Example 1 pattern).
assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != blocking_ep_ptr ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != blocking_ep_ptr ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));

// Container perms: each container is fully pinned by ensures to its pre value;
// addr/is_init are forced by `container_perms_wf` (part of `wf`). Lift to map `=~=`.
assert forall|c: ContainerPtr|
    #![trigger post1_self_.container_perms@[c], post2_self_.container_perms@[c]]
    pre_self_.container_dom().contains(c) implies
        post1_self_.container_perms@[c] == post2_self_.container_perms@[c] by {
    assert(post1_self_.container_dom().contains(c));
    assert(post2_self_.container_dom().contains(c));
    assert(post1_self_.get_container(c) =~= pre_self_.get_container(c));
    assert(post2_self_.get_container(c) =~= pre_self_.get_container(c));
    assert(post1_self_.container_perms@[c].value() =~= post2_self_.container_perms@[c].value());
    assert(post1_self_.container_perms@[c].addr() == c);
    assert(post2_self_.container_perms@[c].addr() == c);
    assert(post1_self_.container_perms@[c].is_init());
    assert(post2_self_.container_perms@[c].is_init());
}
assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);

// Process perms: each process is fully pinned by ensures to its pre value.
assert forall|p: ProcPtr|
    #![trigger post1_self_.process_perms@[p], post2_self_.process_perms@[p]]
    pre_self_.proc_dom().contains(p) implies
        post1_self_.process_perms@[p] == post2_self_.process_perms@[p] by {
    assert(post1_self_.proc_dom().contains(p));
    assert(post2_self_.proc_dom().contains(p));
    assert(post1_self_.get_proc(p) =~= pre_self_.get_proc(p));
    assert(post2_self_.get_proc(p) =~= pre_self_.get_proc(p));
    assert(post1_self_.process_perms@[p].value() =~= post2_self_.process_perms@[p].value());
    assert(post1_self_.process_perms@[p].addr() == p);
    assert(post2_self_.process_perms@[p].addr() == p);
    assert(post1_self_.process_perms@[p].is_init());
    assert(post2_self_.process_perms@[p].is_init());
}
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);

// Thread perms: away from thread_ptr the ensures pin the whole thread value
// to pre's via the `t_ptr != thread_ptr` forall conjunct.
assert forall|t: ThreadPtr|
    #![trigger post1_self_.thread_perms@[t], post2_self_.thread_perms@[t]]
    pre_self_.thread_dom().contains(t) && t != thread_ptr implies
        post1_self_.thread_perms@[t] == post2_self_.thread_perms@[t] by {
    assert(post1_self_.thread_dom().contains(t));
    assert(post2_self_.thread_dom().contains(t));
    assert(pre_self_.get_thread(t) =~= post1_self_.get_thread(t));
    assert(pre_self_.get_thread(t) =~= post2_self_.get_thread(t));
    assert(post1_self_.thread_perms@[t].value() =~= post2_self_.thread_perms@[t].value());
    assert(post1_self_.thread_perms@[t].addr() == t);
    assert(post2_self_.thread_perms@[t].addr() == t);
    assert(post1_self_.thread_perms@[t].is_init());
    assert(post2_self_.thread_perms@[t].is_init());
}

// Endpoint perms: away from blocking_ep_ptr the ensures pin the whole endpoint
// value to pre's via the `e_ptr != blocking_ep_ptr` forall conjunct.
assert forall|e: EndpointPtr|
    #![trigger post1_self_.endpoint_perms@[e], post2_self_.endpoint_perms@[e]]
    pre_self_.endpoint_dom().contains(e) && e != blocking_ep_ptr implies
        post1_self_.endpoint_perms@[e] == post2_self_.endpoint_perms@[e] by {
    assert(post1_self_.endpoint_dom().contains(e));
    assert(post2_self_.endpoint_dom().contains(e));
    assert(pre_self_.get_endpoint(e) =~= post1_self_.get_endpoint(e));
    assert(pre_self_.get_endpoint(e) =~= post2_self_.get_endpoint(e));
    assert(post1_self_.endpoint_perms@[e].value() =~= post2_self_.endpoint_perms@[e].value());
    assert(post1_self_.endpoint_perms@[e].addr() == e);
    assert(post2_self_.endpoint_perms@[e].addr() == e);
    assert(post1_self_.endpoint_perms@[e].is_init());
    assert(post2_self_.endpoint_perms@[e].is_init());
}

// At the modified endpoint, the ensures pin queue@, queue_state, owning_threads
// in both runs; rf_counter is pinned to owning_threads@.len() via endpoint_perms_wf.
assert(post1_self_.endpoint_dom().contains(blocking_ep_ptr));
assert(post2_self_.endpoint_dom().contains(blocking_ep_ptr));
assert(post1_self_.get_endpoint(blocking_ep_ptr).queue@
    =~= post2_self_.get_endpoint(blocking_ep_ptr).queue@);
assert(post1_self_.get_endpoint(blocking_ep_ptr).queue_state
    == post2_self_.get_endpoint(blocking_ep_ptr).queue_state);
assert(post1_self_.get_endpoint(blocking_ep_ptr).owning_threads
    =~= post2_self_.get_endpoint(blocking_ep_ptr).owning_threads);
assert(post1_self_.endpoint_perms@[blocking_ep_ptr].value().rf_counter
    == post2_self_.endpoint_perms@[blocking_ep_ptr].value().rf_counter);
assert(post1_self_.endpoint_perms@[blocking_ep_ptr].addr() == blocking_ep_ptr);
assert(post2_self_.endpoint_perms@[blocking_ep_ptr].addr() == blocking_ep_ptr);
assert(post1_self_.endpoint_perms@[blocking_ep_ptr].is_init());
assert(post2_self_.endpoint_perms@[blocking_ep_ptr].is_init());

// At thread_ptr the ensures pin endpoint_descriptors, ipc_payload, state.
assert(post1_self_.thread_dom().contains(thread_ptr));
assert(post2_self_.thread_dom().contains(thread_ptr));
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= post2_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);
assert(post1_self_.thread_perms@[thread_ptr].addr() == thread_ptr);
assert(post2_self_.thread_perms@[thread_ptr].addr() == thread_ptr);
assert(post1_self_.thread_perms@[thread_ptr].is_init());
assert(post2_self_.thread_perms@[thread_ptr].is_init());
